import{_ as a,o as t,c as r,ae as s}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Credentials (New)","description":"","frontmatter":{"title":"Credentials (New)","slug":"credentials-new"},"headers":[],"relativePath":"account-hub/credentials-new.md","filePath":"account-hub/credentials-new.md"}'),i={name:"account-hub/credentials-new.md"};function n(o,e,c,l,d,h){return t(),r("div",null,[...e[0]||(e[0]=[s('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Credentials tab of the Security &amp; Access page is where you manage authentication credentials for your Branch account.</p><p>You can access this page by navigating to <strong>Configuration &gt; Security &amp; Access &gt;</strong> <a href="https://branchdocs.app.link/security-access-credentials" target="_blank" rel="noreferrer"><strong>Credentials</strong></a> in Branch.</p><div class="danger custom-block"><p class="custom-block-title">Don&#39;t see this page yet?</p><p>The Security &amp; Access page is part of the <a href="./new-branch-overview.html">new Branch</a> experience. This page is being rolled out to customers in phases through 2026. While you&#39;re waiting for access, you can explore this article to familiarize yourself with the new functionality.</p></div><h2 id="credential-types" tabindex="-1">Credential types <a class="header-anchor" href="#credential-types" aria-label="Permalink to &quot;Credential types&quot;">​</a></h2><p>The <strong>Credentials</strong> section displays the authentication credentials needed to access Branch APIs and integrate with external systems. These credentials are essential for programmatic access to your Branch data and for implementing Branch SDKs in your applications.</p><p>Branch provides three types of credentials for different use cases:</p><h3 id="branch-key" tabindex="-1">Branch Key <a class="header-anchor" href="#branch-key" aria-label="Permalink to &quot;Branch Key&quot;">​</a></h3><p>Your Branch Key is a public key used to identify your app. You can think of this as your app&#39;s ID card. You&#39;ll need it to initialize <a href="./branch-sdks.html">Branch SDKs</a> and for basic authentication across <a href="https://help.branch.io/apidocs" target="_blank" rel="noreferrer">Branch APIs</a>.</p><p>Your Branch Key is designed to be used in client-side code and apps, so developers can safely store it in places like GitHub.</p><h3 id="branch-secret" tabindex="-1">Branch Secret <a class="header-anchor" href="#branch-secret" aria-label="Permalink to &quot;Branch Secret&quot;">​</a></h3><p>Your Branch Secret is your app&#39;s <strong>private</strong> authentication credential. This credential is only visible to admins, and it authenticates your app securely for operations like server-side API calls and validating webhook signatures.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Your Branch Secret should only be used in secure, server-side environments. Never include your Branch Secret in client-side code, mobile apps, or any publicly accessible locations.</p></div><h3 id="access-token" tabindex="-1">Access Token <a class="header-anchor" href="#access-token" aria-label="Permalink to &quot;Access Token&quot;">​</a></h3><p>Your Access Token is a unique identifier assigned specifically to you. Each user will have their own Access Token, as long as they have the correct <a href="./user-accounts-and-permissions.html">permissions</a>. The Access Token is used to verify your specific permissions within an organization.</p><p>It&#39;s primarily used for extracting data from certain <a href="https://help.branch.io/apidocs/apis-overview" target="_blank" rel="noreferrer">APIs</a> that require additional authentication.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Your Access Token should only be used in secure, server-side environments. Never include your Access Token in client-side code, mobile apps, or any publicly accessible locations.</p></div><h2 id="view-and-copy-credentials" tabindex="-1">View and copy credentials <a class="header-anchor" href="#view-and-copy-credentials" aria-label="Permalink to &quot;View and copy credentials&quot;">​</a></h2><p>By default, credential values are masked for security. To view and copy your credentials:</p><ol><li>Navigate to <strong>Configuration &gt; Security &amp; Access &gt;</strong> <a href="https://branchdocs.app.link/security-access-credentials" target="_blank" rel="noreferrer"><strong>Credentials</strong></a>.</li><li>Select the <strong>copy icon</strong> next to any credential to copy its value to your clipboard.</li></ol><h2 id="reset-credentials" tabindex="-1">Reset credentials <a class="header-anchor" href="#reset-credentials" aria-label="Permalink to &quot;Reset credentials&quot;">​</a></h2><p>If you suspect a credential has been compromised or need to rotate credentials for security purposes, you can reset any credential using the <strong>Reset</strong> button.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Resetting a credential will immediately invalidate the old value. Any integrations, applications, or scripts using the old credential will stop working until you update them with the new value. Plan your credential rotations carefully to avoid service disruptions.</p></div><p>To reset a credential:</p><ol><li>Select the <strong>Reset</strong> button next to the credential you want to reset.</li><li>Confirm the reset action when prompted.</li><li>Copy the new credential value and update all systems that use it.</li></ol><h2 id="best-practices" tabindex="-1">Best practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best practices&quot;">​</a></h2><p>Follow these best practices when working with Branch credentials:</p><ul><li><strong>Store credentials securely</strong>: Developers should use environment variables or secure credential management systems rather than hardcoding credentials in your codebase.</li><li><strong>Limit credential access</strong>: Only share credentials with team members who require them for their work.</li><li><strong>Rotate regularly</strong>: Consider resetting credentials periodically as part of your security hygiene.</li><li><strong>Monitor usage</strong>: Keep track of where credentials are used so you can update them quickly if needed.</li><li><strong>Use appropriate credentials</strong>: Always use the Branch Key for client-side implementations and reserve the Branch Secret for server-side operations.</li></ul>',28)])])}const y=a(i,[["render",n]]);export{u as __pageData,y as default};
